import { useState, useEffect } from 'react';
import { 
  Play, 
  RotateCcw, 
  Mic, 
  Image, 
  FileText, 
  Film, 
  ChevronRight, 
  Zap, 
  Terminal,
  AlertCircle,
  CheckCircle2,
  Loader2
} from 'lucide-react';

// 类型定义
interface VideoProject {
  id: string;
  date: string;
  topic: string;
  status: 'pending' | 'script' | 'voice' | 'images' | 'timeline' | 'composing' | 'completed' | 'error';
  progress: number;
  script?: {
    wordCount: number;
    duration: number;
  };
  images?: {
    count: number;
    completed: number;
  };
  voice?: {
    duration: number;
  };
}

interface AgentStatus {
  name: string;
  status: 'idle' | 'running' | 'completed' | 'error';
  progress: number;
  message: string;
  lastRun?: string;
}

interface LogEntry {
  time: string;
  message: string;
  type: 'info' | 'success' | 'error' | 'warning';
}

// 项目数据
const PROJECTS: VideoProject[] = [
  {
    id: 'video2-openclaw-guide',
    date: '2026-02-27',
    topic: '《OpenClaw高阶进化指南》',
    status: 'images',
    progress: 60,
    script: { wordCount: 2200, duration: 600 },
    images: { count: 13, completed: 13 },
    voice: { duration: 600 },
  },
  {
    id: 'video-factory-v3',
    date: '2026-02-26',
    topic: 'OpenClaw自动化实战 (90秒版)',
    status: 'completed',
    progress: 100,
    script: { wordCount: 228, duration: 90 },
    images: { count: 5, completed: 5 },
    voice: { duration: 90 },
  }
];

// Agent状态
const AGENTS: AgentStatus[] = [
  { name: '脚本创作', status: 'completed', progress: 100, message: '✓ 口播稿已生成 (2200字/10分钟)', lastRun: '2026-02-25 12:11' },
  { name: '语音合成', status: 'completed', progress: 100, message: '✓ CosyVoice音频已生成', lastRun: '2026-02-25 12:15' },
  { name: '配图生成', status: 'running', progress: 100, message: '⏳ 13张配图已生成 (100%)', lastRun: '2026-02-26 21:32' },
  { name: '时间轴', status: 'idle', progress: 0, message: '等待执行' },
  { name: '视频合成', status: 'idle', progress: 0, message: '等待执行' },
];

// 状态样式
const statusColors = {
  idle: 'bg-gray-500/20 border-gray-500/30',
  running: 'bg-yellow-500/20 border-yellow-500/30',
  completed: 'bg-green-500/20 border-green-500/30',
  error: 'bg-red-500/20 border-red-500/30',
};

const statusLabels = {
  pending: '等待中',
  script: '脚本创作',
  voice: '语音合成',
  images: '配图生成',
  timeline: '时间轴',
  composing: '视频合成',
  completed: '已完成',
  error: '错误',
};

const statusIcons = {
  idle: AlertCircle,
  running: Loader2,
  completed: CheckCircle2,
  error: AlertCircle,
};

function App() {
  const [selectedProject, setSelectedProject] = useState<VideoProject>(PROJECTS[0]);
  const [agents, setAgents] = useState<AgentStatus[]>(AGENTS);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [isRunningAll, setIsRunningAll] = useState(false);

  // 添加日志
  const addLog = (message: string, type: LogEntry['type'] = 'info') => {
    const time = new Date().toLocaleTimeString('zh-CN');
    setLogs(prev => [...prev, { time, message, type }]);
  };

  // 触发Agent
  const triggerAgent = async (agentName: string) => {
    addLog(`启动 ${agentName}...`, 'info');
    
    // 更新Agent状态
    setAgents(prev => prev.map(a => 
      a.name === agentName 
        ? { ...a, status: 'running' as const, message: '执行中...' }
        : a
    ));

    // 模拟执行
    await new Promise(resolve => setTimeout(resolve, 1500));
    
    addLog(`${agentName} 执行完成`, 'success');
    
    setAgents(prev => prev.map(a => 
      a.name === agentName 
        ? { ...a, status: 'completed' as const, progress: 100, message: '✓ 已完成', lastRun: new Date().toLocaleString('zh-CN') }
        : a
    ));
  };

  // 一键运行所有Agent
  const runAllAgents = async () => {
    setIsRunningAll(true);
    addLog('🚀 启动所有Agent...', 'info');
    
    for (const agent of agents) {
      if (agent.status !== 'completed') {
        await triggerAgent(agent.name);
        await new Promise(resolve => setTimeout(resolve, 500));
      }
    }
    
    addLog('✅ 所有Agent执行完成', 'success');
    setIsRunningAll(false);
  };

  // 初始化日志
  useEffect(() => {
    addLog('工作台已加载', 'info');
    addLog(`当前项目: ${selectedProject.topic}`, 'info');
  }, []);

  return (
    <div className="min-h-screen bg-gradient-to-br from-cyber-dark via-[#0f0f1a] to-[#1a1a2e]">
      {/* Header */}
      <header className="sticky top-0 z-50 glass border-b border-cyber-purple/30">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-cyber-purple to-cyber-cyan flex items-center justify-center">
                <Film className="w-5 h-5 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold bg-gradient-to-r from-cyber-purple to-cyber-cyan bg-clip-text text-transparent">
                  AI厂长视频工厂
                </h1>
                <p className="text-xs text-gray-400">Vite + React + Tailwind</p>
              </div>
            </div>
            <div className="flex gap-2">
              <button 
                onClick={runAllAgents}
                disabled={isRunningAll}
                className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-cyber-purple to-cyber-cyan rounded-lg text-sm font-medium hover:opacity-90 transition disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isRunningAll ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    运行中...
                  </>
                ) : (
                  <>
                    <Zap className="w-4 h-4" />
                    一键运行所有Agent
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6">
        {/* Agent状态 */}
        <section className="mb-6">
          <h2 className="text-sm font-semibold text-gray-400 mb-3 uppercase tracking-wider">
            Agent状态 (点击触发)
          </h2>
          <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
            {agents.map((agent) => {
              const StatusIcon = statusIcons[agent.status];
              return (
                <div 
                  key={agent.name}
                  onClick={() => !isRunningAll && triggerAgent(agent.name)}
                  className={`p-4 rounded-xl border backdrop-blur-sm cursor-pointer transition-all hover:scale-105 ${statusColors[agent.status]}`}
                >
                  <div className="flex items-center gap-2 mb-2">
                    <StatusIcon className={`w-4 h-4 ${agent.status === 'running' ? 'animate-spin' : ''}`} />
                    <span className="text-sm font-medium">{agent.name}</span>
                  </div>
                  <div className="text-xs text-gray-400 mb-2 truncate">{agent.message}</div>
                  <div className="w-full bg-gray-700/50 rounded-full h-1.5">
                    <div
                      className="progress-bar h-1.5 rounded-full transition-all duration-500"
                      style={{ width: `${agent.progress}%` }}
                    />
                  </div>
                  {agent.lastRun && (
                    <div className="text-xs text-gray-500 mt-1">{agent.lastRun}</div>
                  )}
                </div>
              );
            })}
          </div>
        </section>

        <div className="grid lg:grid-cols-3 gap-6">
          {/* 项目列表 */}
          <section className="lg:col-span-1">
            <h2 className="text-sm font-semibold text-gray-400 mb-3 uppercase tracking-wider">项目列表</h2>
            <div className="space-y-3">
              {PROJECTS.map((project) => (
                <div
                  key={project.id}
                  onClick={() => setSelectedProject(project)}
                  className={`p-4 rounded-xl border cursor-pointer transition-all ${
                    selectedProject.id === project.id
                      ? 'bg-cyber-purple/10 border-cyber-purple'
                      : 'glass hover:bg-white/10'
                  }`}
                >
                  <div className="flex items-start justify-between mb-2">
                    <div>
                      <div className="font-medium text-sm truncate">{project.topic}</div>
                      <div className="text-xs text-gray-500">{project.date}</div>
                    </div>
                    <ChevronRight 
                      className={`w-4 h-4 transition-transform ${selectedProject.id === project.id ? 'rotate-90' : ''}`} 
                    />
                  </div>
                  <div className="flex items-center justify-between">
                    <span className={`text-xs ${
                      project.status === 'completed' ? 'text-green-400' : 
                      project.status === 'error' ? 'text-red-400' : 'text-cyber-cyan'
                    }`}>
                      {statusLabels[project.status]}
                    </span>
                    <span className="text-xs text-gray-500">{project.progress}%</span>
                  </div>
                  <div className="mt-2 w-full bg-gray-700/50 rounded-full h-1">
                    <div
                      className="progress-bar h-1 rounded-full transition-all"
                      style={{ width: `${project.progress}%` }}
                    />
                  </div>
                </div>
              ))}
            </div>
          </section>

          {/* 详情 + 控制台 */}
          <section className="lg:col-span-2 space-y-4">
            {/* 项目详情 */}
            <div className="glass rounded-xl p-6">
              <div className="flex items-center justify-between mb-6">
                <div>
                  <h2 className="text-xl font-bold">{selectedProject.topic}</h2>
                  <p className="text-sm text-gray-400">创建于 {selectedProject.date}</p>
                </div>
                <div className="flex gap-2">
                  <button className="p-2 bg-cyber-purple/20 border border-cyber-purple rounded-lg hover:bg-cyber-purple/30 transition">
                    <Play className="w-4 h-4" />
                  </button>
                  <button className="p-2 bg-gray-700/50 border border-gray-600 rounded-lg hover:bg-gray-700 transition">
                    <RotateCcw className="w-4 h-4" />
                  </button>
                </div>
              </div>

              <div className="space-y-4">
                {/* 口播稿 */}
                <div className="border-l-2 border-cyber-purple/30 pl-4">
                  <div className="flex items-center gap-2 mb-2">
                    <FileText className="w-4 h-4 text-cyber-cyan" />
                    <span className="font-medium">口播稿</span>
                    <CheckCircle2 className="w-4 h-4 text-green-400" />
                  </div>
                  <div className="text-xs text-gray-500">
                    {selectedProject.script?.wordCount}字 · {selectedProject.script?.duration}秒
                  </div>
                </div>

                {/* 配图 */}
                <div className="border-l-2 border-cyber-purple/30 pl-4">
                  <div className="flex items-center gap-2 mb-2">
                    <Image className="w-4 h-4 text-cyber-cyan" />
                    <span className="font-medium">PPT配图 ({selectedProject.images?.completed}/{selectedProject.images?.count}张)</span>
                    <CheckCircle2 className="w-4 h-4 text-green-400" />
                  </div>
                  <div className="grid grid-cols-6 gap-2">
                    {Array.from({ length: Math.min(selectedProject.images?.count || 0, 12) }, (_, i) => (
                      <div 
                        key={i} 
                        className="aspect-video bg-gradient-to-br from-cyber-purple/20 to-cyber-cyan/20 rounded flex items-center justify-center text-xs"
                      >
                        P{i + 1}
                      </div>
                    ))}
                    {(selectedProject.images?.count || 0) > 12 && (
                      <div className="aspect-video bg-white/10 rounded flex items-center justify-center text-xs">
                        +{(selectedProject.images?.count || 0) - 12}
                      </div>
                    )}
                  </div>
                </div>

                {/* 语音 */}
                <div className="border-l-2 border-cyber-purple/30 pl-4">
                  <div className="flex items-center gap-2 mb-2">
                    <Mic className="w-4 h-4 text-cyber-cyan" />
                    <span className="font-medium">语音合成</span>
                    <CheckCircle2 className="w-4 h-4 text-green-400" />
                  </div>
                  <div className="text-xs text-gray-500">总时长: {selectedProject.voice?.duration}秒</div>
                </div>
              </div>
            </div>

            {/* 控制台 */}
            <div className="glass rounded-xl p-4">
              <div className="flex items-center gap-2 mb-3">
                <Terminal className="w-4 h-4 text-cyber-cyan" />
                <span className="text-sm font-medium">控制台输出</span>
                <span className="text-xs text-gray-500 ml-auto">{logs.length} 条日志</span>
              </div>
              <div className="font-mono text-xs space-y-1 max-h-48 overflow-y-auto">
                {logs.length === 0 ? (
                  <span className="text-gray-500">等待操作...</span>
                ) : (
                  logs.map((log, i) => (
                    <div 
                      key={i} 
                      className={`${
                        log.type === 'error' ? 'text-red-400' :
                        log.type === 'success' ? 'text-green-400' :
                        log.type === 'warning' ? 'text-yellow-400' :
                        'text-cyber-cyan/80'
                      }`}
                    >
                      <span className="text-gray-500">[{log.time}]</span> {log.message}
                    </div>
                  ))
                )}
              </div>
            </div>
          </section>
        </div>
      </main>
    </div>
  );
}

export default App;